@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: hsl(var(--background));
  --color-foreground: hsl(var(--foreground));
  --font-sans: var(--font-manrope);
  --font-mono: var(--font-jetbrains-mono);
  --font-heading: var(--font-manrope);
  --color-sidebar-ring: hsl(var(--sidebar-ring));
  --color-sidebar-border: hsl(var(--sidebar-border));
  --color-sidebar-accent-foreground: hsl(var(--sidebar-accent-foreground));
  --color-sidebar-accent: hsl(var(--sidebar-accent));
  --color-sidebar-primary-foreground: hsl(var(--sidebar-primary-foreground));
  --color-sidebar-primary: hsl(var(--sidebar-primary));
  --color-sidebar-foreground: hsl(var(--sidebar-foreground));
  --color-sidebar: hsl(var(--sidebar));
  --color-chart-5: hsl(var(--chart-5));
  --color-chart-4: hsl(var(--chart-4));
  --color-chart-3: hsl(var(--chart-3));
  --color-chart-2: hsl(var(--chart-2));
  --color-chart-1: hsl(var(--chart-1));
  --color-ring: hsl(var(--ring));
  --color-input: hsl(var(--input));
  --color-border: hsl(var(--border));
  --color-destructive: hsl(var(--destructive));
  --color-destructive-foreground: hsl(var(--destructive-foreground));
  --color-accent-foreground: hsl(var(--accent-foreground));
  --color-accent: hsl(var(--accent));
  --color-muted-foreground: hsl(var(--muted-foreground));
  --color-muted: hsl(var(--muted));
  --color-secondary-foreground: hsl(var(--secondary-foreground));
  --color-secondary: hsl(var(--secondary));
  --color-primary-foreground: hsl(var(--primary-foreground));
  --color-primary: hsl(var(--primary));
  --color-popover-foreground: hsl(var(--popover-foreground));
  --color-popover: hsl(var(--popover));
  --color-card-foreground: hsl(var(--card-foreground));
  --color-card: hsl(var(--card));
  --color-header-background: hsl(var(--header-background));
  --color-header-foreground: hsl(var(--header-foreground));
  --color-panel-background: hsl(var(--panel-background));
  --color-panel-foreground: hsl(var(--panel-foreground));
  --color-panel-muted: hsl(var(--panel-muted));
  --color-surface-1: hsl(var(--surface-1));
  --color-surface-2: hsl(var(--surface-2));
  --color-surface-3: hsl(var(--surface-3));
  --color-table-header: hsl(var(--table-header));
  --color-table-row-hover: hsl(var(--table-row-hover));
  --color-success: hsl(var(--success));
  --color-warning: hsl(var(--warning));
  --color-info: hsl(var(--info));
  --color-sidebar-background: hsl(var(--sidebar-background));
  --color-sidebar-active-background: hsl(var(--sidebar-active-background));
  --color-sidebar-active-foreground: hsl(var(--sidebar-active-foreground));
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);
}

:root {
  --background: 24 24% 97%;
  --foreground: 234 22% 14%;
  --card: 0 0% 100%;
  --card-foreground: 234 22% 14%;
  --popover: 0 0% 100%;
  --popover-foreground: 234 22% 14%;
  --primary: 0 99% 56%;
  --primary-foreground: 0 0% 100%;
  --secondary: 18 28% 95%;
  --secondary-foreground: 234 19% 17%;
  --muted: 18 20% 93%;
  --muted-foreground: 232 10% 42%;
  --accent: 14 24% 94%;
  --accent-foreground: 234 18% 16%;
  --destructive: 3 76% 57%;
  --destructive-foreground: 0 0% 99%;
  --border: 16 18% 86%;
  --input: 16 20% 88%;
  --ring: 0 99% 56%;
  --radius: 1.1rem;
  --header-background: 0 0% 100%;
  --header-foreground: 234 22% 14%;
  --panel-background: 0 0% 100%;
  --panel-foreground: 234 22% 14%;
  --panel-muted: 14 24% 95%;
  --surface-1: 24 24% 97%;
  --surface-2: 0 0% 100%;
  --surface-3: 18 28% 96%;
  --table-header: 14 26% 95%;
  --table-row-hover: 10 34% 96%;
  --success: 151 56% 43%;
  --warning: 39 91% 54%;
  --info: 204 82% 56%;
  --chart-1: 0 99% 56%;
  --chart-2: 6 88% 62%;
  --chart-3: 229 61% 58%;
  --chart-4: 153 53% 42%;
  --chart-5: 240 22% 18%;
  --sidebar-background: 18 24% 99%;
  --sidebar-foreground: 234 24% 18%;
  --sidebar-border: 16 16% 89%;
  --sidebar-active-background: 0 100% 96%;
  --sidebar-active-foreground: 0 80% 43%;
  --sidebar: var(--sidebar-background);
  --sidebar-primary: 0 99% 56%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 14 24% 95%;
  --sidebar-accent-foreground: 234 20% 18%;
  --sidebar-ring: var(--ring);
  --shadow-soft:
    0 16px 36px -24px hsl(8 26% 18% / 0.16),
    0 10px 24px -18px hsl(8 26% 18% / 0.1);
  --shadow-panel:
    0 24px 48px -28px hsl(8 24% 16% / 0.18),
    0 10px 30px -22px hsl(8 24% 16% / 0.08),
    inset 0 1px 0 hsl(0 0% 100% / 0.7);
}

.dark {
  --background: 18 8% 8%;
  --foreground: 210 24% 96%;
  --card: 18 6% 11%;
  --card-foreground: 210 24% 96%;
  --popover: 18 6% 11%;
  --popover-foreground: 210 24% 96%;
  --primary: 0 99% 56%;
  --primary-foreground: 0 0% 100%;
  --secondary: 18 5% 16%;
  --secondary-foreground: 210 22% 92%;
  --muted: 18 5% 16%;
  --muted-foreground: 16 8% 68%;
  --accent: 18 5% 17%;
  --accent-foreground: 210 24% 96%;
  --destructive: 3 80% 60%;
  --destructive-foreground: 0 0% 99%;
  --border: 18 4% 20%;
  --input: 18 4% 18%;
  --ring: 0 99% 56%;
  --header-background: 18 7% 9%;
  --header-foreground: 210 24% 96%;
  --panel-background: 18 6% 11%;
  --panel-foreground: 210 24% 96%;
  --panel-muted: 18 5% 15%;
  --surface-1: 18 8% 8%;
  --surface-2: 18 6% 11%;
  --surface-3: 18 5% 14%;
  --table-header: 18 5% 14%;
  --table-row-hover: 18 5% 16%;
  --success: 151 58% 46%;
  --warning: 39 92% 57%;
  --info: 224 80% 68%;
  --chart-1: 0 99% 56%;
  --chart-2: 7 88% 62%;
  --chart-3: 226 66% 64%;
  --chart-4: 152 49% 44%;
  --chart-5: 240 22% 18%;
  --sidebar-background: 20 6% 8%;
  --sidebar-foreground: 214 20% 92%;
  --sidebar-border: 18 4% 16%;
  --sidebar-active-background: 0 42% 16%;
  --sidebar-active-foreground: 0 94% 70%;
  --sidebar: var(--sidebar-background);
  --sidebar-primary: 0 99% 56%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 18 5% 15%;
  --sidebar-accent-foreground: 214 20% 92%;
  --sidebar-ring: var(--ring);
  --shadow-soft:
    0 18px 46px -28px hsl(0 0% 1% / 0.76),
    0 10px 24px -18px hsl(0 0% 1% / 0.56);
  --shadow-panel:
    0 28px 72px -34px hsl(0 0% 1% / 0.88),
    0 12px 30px -24px hsl(0 0% 1% / 0.62),
    inset 0 1px 0 hsl(0 0% 100% / 0.03);
}

@layer base {
  html,
  body {
    min-height: 100%;
  }

  * {
    @apply border-border outline-ring/50;
  }

  *::selection {
    background: hsl(var(--primary) / 0.22);
    color: hsl(var(--foreground));
  }

  body {
    @apply bg-background text-foreground;
    background-image:
      radial-gradient(circle at top left, hsl(var(--primary) / 0.14), transparent 24%),
      radial-gradient(circle at top right, hsl(var(--primary) / 0.08), transparent 24%),
      linear-gradient(180deg, hsl(var(--surface-1)) 0%, hsl(var(--background)) 52%, hsl(var(--surface-1)) 100%);
    letter-spacing: -0.01em;
  }

  html {
    @apply font-sans;
  }

  h1,
  h2,
  h3,
  h4 {
    @apply font-heading;
    letter-spacing: -0.03em;
  }

  code,
  kbd,
  samp {
    @apply font-mono;
  }
}

@layer utilities {
  .shadow-soft {
    box-shadow: var(--shadow-soft);
  }

  .shadow-panel {
    box-shadow: var(--shadow-panel);
  }

  .surface-grid {
    background-image:
      linear-gradient(to right, hsl(var(--border) / 0.14) 1px, transparent 1px),
      linear-gradient(to bottom, hsl(var(--border) / 0.14) 1px, transparent 1px);
    background-size: 112px 112px;
  }

  .surface-dot {
    background-image:
      radial-gradient(hsl(var(--border) / 0.34) 0.8px, transparent 0.8px);
    background-size: 18px 18px;
  }
}

import type { Metadata } from "next";
import { JetBrains_Mono, Manrope } from "next/font/google";
import { ThemeProvider } from "@/components/theme/theme-provider";
import { TooltipProvider } from "@/components/ui/tooltip";
import "./globals.css";

const manrope = Manrope({
  variable: "--font-manrope",
  subsets: ["latin"],
});

const jetbrainsMono = JetBrains_Mono({
  variable: "--font-jetbrains-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: {
    default: "Red Taxi Admin",
    template: "%s | Red Taxi Admin",
  },
  description:
    "Premium operations dashboard foundation for Red Taxi transport and dispatch management.",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html
      lang="en"
      suppressHydrationWarning
      className={`${manrope.variable} ${jetbrainsMono.variable} h-full scroll-smooth`}
    >
      <body className="min-h-full bg-background font-sans text-foreground antialiased">
        <ThemeProvider
          attribute="class"
          defaultTheme="dark"
          enableSystem
          disableTransitionOnChange
        >
          <TooltipProvider delayDuration={150}>{children}</TooltipProvider>
        </ThemeProvider>
      </body>
    </html>
  );
}

"use client";

import type { ThemeProviderProps } from "next-themes";
import { ThemeProvider as NextThemesProvider } from "next-themes";

export function ThemeProvider({ children, ...props }: ThemeProviderProps) {
  return <NextThemesProvider {...props}>{children}</NextThemesProvider>;
}

"use client";

import { Laptop, MoonStar, SunMedium } from "lucide-react";
import { useTheme } from "next-themes";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

const THEME_OPTIONS = [
  {
    icon: SunMedium,
    label: "Light",
    value: "light" as const,
  },
  {
    icon: MoonStar,
    label: "Dark",
    value: "dark" as const,
  },
  {
    icon: Laptop,
    label: "System",
    value: "system" as const,
  },
];

export function ThemeToggle() {
  const { setTheme } = useTheme();

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="relative rounded-full border border-border/70 bg-surface-2 text-muted-foreground shadow-soft hover:bg-surface-3 hover:text-foreground"
          aria-label="Toggle theme"
        >
          <SunMedium className="size-4 transition-all dark:scale-0 dark:-rotate-90" />
          <MoonStar className="absolute size-4 scale-0 rotate-90 transition-all dark:scale-100 dark:rotate-0" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent className="w-40" align="end">
        <DropdownMenuLabel>Appearance</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {THEME_OPTIONS.map((option) => {
          const Icon = option.icon;

          return (
            <DropdownMenuItem
              key={option.value}
              onClick={() => setTheme(option.value)}
              className="gap-2"
            >
              <Icon className="size-4" />
              {option.label}
            </DropdownMenuItem>
          );
        })}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
